// (2) reset_n: Asynchronous reset of the counter. Active low.
// (3) clk: Clock signal.
// (4) q: 7-bit output of the counter.
module top_module(
	input clk,
	input enable,
	input reset,
	output reg [6:0] q);always @(posedge clk or posedge reset) begin
	if (reset)
		q <= 7'b0000000;
	else if (enable)
		q <= q + 4;
end
endmodule

